namespace sv_2c7335e9e5f0432fa95584819e2cb92b.Models;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

using sv_2c7335e9e5f0432fa95584819e2cb92b.Models;

namespace sv_2c7335e9e5f0432fa95584819e2cb92b.Services;

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@rendermode InteractiveServer
@using sv_2c7335e9e5f0432fa95584819e2cb92b.Models
@using sv_2c7335e9e5f0432fa95584819e2cb92b.Services
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="container-fluid">
    <div class="row">
        <!-- Sidebar Filters -->
        <aside class="col-lg-3 mb-4">
            <div class="card">
                <div class="card-header fw-bold">Filters</div>
                <div class="card-body">
                    @if (categories is not null)
                    {
                        <h6>Category</h6>
                        <div class="mb-3">
                            @foreach (var cat in categories)
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                           checked="@selectedCategories.Contains(cat)"
                                           @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                                    <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                                </div>
                            }
                        </div>
                    }

                    <h6>Price Range</h6>
                    <div class="row g-2 mb-3">
                        <div class="col-6">
                            <input type="number" class="form-control form-control-sm" placeholder="Min"
                                   @bind="minPrice" min="0" step="0.01" />
                        </div>
                        <div class="col-6">
                            <input type="number" class="form-control form-control-sm" placeholder="Max"
                                   @bind="maxPrice" min="0" step="0.01" />
                        </div>
                    </div>

                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
                    </div>
                </div>
            </div>
        </aside>

        <!-- Main Content -->
        <main class="col-lg-9">
            @if (errorMessage is not null)
            {
                <div class="alert alert-danger" role="alert">
                    <strong>Error:</strong> @errorMessage
                </div>
            }
            else if (isLoading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary me-2" role="status"></div>
                    <span>Loading products…</span>
                </div>
            }
            else if (result is not null && result.Items.Count == 0)
            {
                <div class="alert alert-info" role="alert">
                    No products found matching your criteria. Try adjusting the filters.
                </div>
            }
            else if (result is not null)
            {
                <!-- Toolbar -->
                <div class="d-flex justify-content-between align-items-center mb-3">
                    <div>
                        <label class="form-label me-2 mb-0">Sort by:</label>
                        <select class="form-select form-select-sm d-inline-block w-auto" @bind="sortBy" @bind:after="OnSortChanged">
                            <option value="price_asc">Price: Low to High</option>
                            <option value="price_desc">Price: High to Low</option>
                            <option value="name_asc">Name: A-Z</option>
                            <option value="rating_desc">Rating: Highest</option>
                        </select>
                    </div>
                    <span class="text-muted">
                        Showing @(((result.Page - 1) * result.PageSize) + 1)–@(Math.Min(result.Page * result.PageSize, result.TotalCount))
                        of @result.TotalCount products
                    </span>
                </div>

                <!-- Product Grid -->
                <div class="row row-cols-1 row-cols-md-2 row-cols-xl-3 g-3 mb-4">
                    @foreach (var product in result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="OnProductSelected"
                                         OnAddToCart="OnAddToCart" />
                        </div>
                    }
                </div>

                <!-- Pagination -->
                @{
                    int totalPages = (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
                }
                @if (totalPages > 1)
                {
                    <nav aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage - 1)" disabled="@(currentPage == 1)">
                                    Previous
                                </button>
                            </li>
                            @for (int i = 1; i <= totalPages; i++)
                            {
                                int pageNum = i;
                                <li class="page-item @(pageNum == currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                                </li>
                            }
                            <li class="page-item @(currentPage == totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage + 1)" disabled="@(currentPage == totalPages)">
                                    Next
                                </button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </main>
    </div>
</div>

@code {
    [Parameter] public EventCallback<int> OnProductSelected { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = LoadProducts();
            await Task.WhenAll(categoriesTask, searchTask);
            categories = await categoriesTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private async Task OnAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        await Task.CompletedTask;
    }
}

@using sv_2c7335e9e5f0432fa95584819e2cb92b.Models

<div class="card h-100 product-card" @onclick="() => OnProductSelected.InvokeAsync(Product.Id)" role="button">
    <div class="card-img-top bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
         style="height: 180px;" title="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2">
            @for (int i = 1; i <= 5; i++)
            {
                <span class="@(i <= Math.Round(Product.Rating) ? "text-warning" : "text-muted")">★</span>
            }
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Product Product { get; set; } = default!;
    [Parameter] public EventCallback<int> OnProductSelected { get; set; }
    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleAddToCart()
    {
        await OnAddToCart.InvokeAsync(Product);
    }
}

