@using sv_2c7335e9e5f0432fa95584819e2cb92b.Models

<div class="card h-100 product-card" @onclick="() => OnProductSelected.InvokeAsync(Product.Id)" role="button">
    <div class="card-img-top bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
         style="height: 180px;" title="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2">
            @for (int i = 1; i <= 5; i++)
            {
                <span class="@(i <= Math.Round(Product.Rating) ? "text-warning" : "text-muted")">★</span>
            }
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Product Product { get; set; } = default!;
    [Parameter] public EventCallback<int> OnProductSelected { get; set; }
    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleAddToCart()
    {
        await OnAddToCart.InvokeAsync(Product);
    }
}

